3	 *
4	 * Module map
5	 * ──────────
6	 *   api.js          HTTP client + token management
7	 *   utils.js        Shared UI helpers
8	 *   auth.js         Login / Register
9	 *   dashboard.js    User dashboard
10	 *   matching.js     Peer search, sessions, queue + polling
11	 *   verification.js Identity verification panel
12	 *   ledger.js       Transaction history + transfer
13	 *   admin.js        Admin views (dashboard, users, violations, etc.)
14	 */
