33	import { API as _api } from './api.js';
34	
35	// ---- Expose helpers on App global so onclick= attributes can call them ----
36	window.App = {
37	  navigate,
38	  openRequestSession,
39	  openRateSession,
40	  viewRepModal,
41	  adminManageUser,
42	  adminCreditModal,
43	  reviewVerification,
44	  resolveViolation,
