61	  'admin-sessions':      renderAdminSessions,
62	  'ledger-verify':       renderVerifyChains,
63	  'audit-logs':          renderAuditLogs,
64	};
65	
66	// ---- Navigation ---------------------------------------------------------
67	export function navigate(view) {
68	  // Enforce role access
69	  const user = API.loadUser();
70	  const adminOnly  = ['admin-dashboard','admin-users','admin-verifications',
71	                      'admin-violations','admin-sessions'];
72	  const staffOnly  = ['audit-logs','ledger-verify'];
73	  if (adminOnly.includes(view) && user?.role !== 'admin') {
74	    showAlert('Admin access required.', 'error');
75	    return;
76	  }
77	  if (staffOnly.includes(view) && !['admin','auditor'].includes(user?.role)) {
78	    showAlert('Admin or Auditor access required.', 'error');
79	    return;
80	  }
81	
82	  qsa('[data-view]').forEach(a =>
83	    a.classList.toggle('active', a.dataset.view === view));
84	
85	  const fn = ROUTES[view];
86	  if (fn) fn();
87	  else el('view-container').innerHTML =
88	    `<div class="alert alert-error">View "${view}" not found.</div>`;
89	}
