115	      <input id="mp-offered" type="text"
116	        value="${(prof?.skills_offered ?? []).join(', ')}">
117	    </div>
118	    <div class="form-group">
119	      <label>Skills I Need</label>
120	      <input id="mp-needed" type="text"
121	        value="${(prof?.skills_needed ?? []).join(', ')}">
122	    </div>
123	    <div class="form-group">
124	      <label>Bio</label>
125	      <textarea id="mp-bio" rows="3">${prof?.bio || ''}</textarea>
126	    </div>
127	    <div class="form-group" style="display:flex;align-items:center;gap:.5rem">
128	      <input type="checkbox" id="mp-active" ${prof?.is_active !== 0 ? 'checked' : ''}
129	             style="width:auto">
130	      <label for="mp-active" style="margin:0;color:var(--c-text)">
131	        Appear in peer search
