1	/**
2	 * matching.js — Peer search, session lifecycle, and queue with live polling.
3	 *
4	 * Match States
5	 * ────────────
6	 *   searching  → polling every 10 s, spinner shown
7	 *   found      → matched! session link displayed, polling stopped
8	 *   retrying   → entry expired/cancelled, user offered to rejoin
9	 */
10	
11	import { API } from './api.js';
12	import { el, qs, qsa, badge, stars, fmtDate,
13	         showAlert, showModal, closeModal,
14	         buildPagination, loadingHTML, emptyHTML } from './utils.js';
15	
16	// ---- Polling state -------------------------------------------------------
17	let _pollTimer    = null;
18	let _pollEntryId  = null;
19	let _pollSkill    = '';
20	let _pollAttempts = 0;
21	const POLL_INTERVAL_MS = 10_000;
22	
23	function startPolling(entryId, skill) {
24	  stopPolling();
25	  _pollEntryId  = entryId;
26	  _pollSkill    = skill;
27	  _pollAttempts = 0;
28	  _pollTimer    = setInterval(_pollQueueEntry, POLL_INTERVAL_MS);
29	}
30	
31	function stopPolling() {
32	  if (_pollTimer) { clearInterval(_pollTimer); _pollTimer = null; }
33	  _pollEntryId = null;
34	}
35	
36	async function _pollQueueEntry() {
37	  if (!_pollEntryId) return;
38	  _pollAttempts++;
39	
40	  const { ok, data } = await API.get(`/matching/queue/${_pollEntryId}`);
41	  if (!ok) return; // network hiccup — keep trying
42	
43	  const entry  = data.entry;
44	  const card   = el('match-status-card');
45	  const meta   = el('poll-meta');
46	  if (meta) meta.textContent = `Last checked: just now · attempt ${_pollAttempts}`;
47	
48	  if (entry.status === 'matched') {
49	    stopPolling();
50	    _renderMatchState(card, 'found', entry);
51	  } else if (entry.status === 'expired' || entry.status === 'cancelled') {
52	    stopPolling();
53	    _renderMatchState(card, 'retrying', entry);
54	  }
55	  // else still 'waiting' — leave 'searching' state as-is
56	}
57	
58	function _renderMatchState(card, state, entry) {
59	  if (!card) return;
60	  card.className = `match-status-card state-${state}`;
61	
62	  const content = {
63	    found: `
64	      <div class="state-icon">✅</div>
65	      <h3 style="color:var(--c-success)">Match Found!</h3>
66	      <p>You've been matched for <strong>${entry.skill}</strong>.</p>
67	      <a class="btn btn-success btn-lg" href="#" onclick="App.navigate('sessions')">
68	        View Session →
69	      </a>
70	      <div class="match-poll-meta">Session #${entry.session_id}</div>`,
71	
72	    retrying: `
73	      <div class="state-icon">🔄</div>
74	      <h3 style="color:var(--c-warn)">No Match Yet</h3>
75	      <p>Your queue entry expired. Try joining again.</p>
76	      <button class="btn btn-warn btn-lg" id="btn-rejoin">Rejoin Queue</button>
77	      <div class="match-poll-meta">Skill: ${entry.skill}</div>`,
78	
79	    searching: `
80	      <div class="state-icon pulse"><div class="spinner" style="margin:0 auto"></div></div>
81	      <h3 style="color:var(--c-accent);margin-top:.5rem">Searching…</h3>
82	      <p>Looking for a peer who offers <strong>${entry.skill}</strong>.</p>
83	      <button class="btn btn-ghost btn-sm" id="btn-cancel-queue">Cancel</button>
84	      <div class="match-poll-meta" id="poll-meta">Polling every 10 s</div>`,
85	  };
86	
87	  card.innerHTML = content[state] || '';
88	
89	  if (state === 'retrying') {
90	    el('btn-rejoin')?.addEventListener('click', () => {
91	      renderQueueSection(entry.skill);
92	    });
93	  }
94	  if (state === 'searching') {
95	    el('btn-cancel-queue')?.addEventListener('click', async () => {
96	      await API.put(`/matching/queue/${_pollEntryId}/cancel`);
97	      stopPolling();
98	      card.remove();
99	      showAlert('Queue entry cancelled.', 'info');
100	    });
101	  }
102	}
