1	/**
2	 * api.js — Centralised HTTP client.
3	 * Manages the JWT token and wraps fetch with auth headers.
4	 */
5	
6	const TOKEN_KEY = 'pex_token';
7	const USER_KEY  = 'pex_user';
8	
9	export const API = {
10	  _token: localStorage.getItem(TOKEN_KEY),
11	
12	  setToken(t)   { this._token = t; localStorage.setItem(TOKEN_KEY, t); },
13	  clearToken()  { this._token = null; localStorage.removeItem(TOKEN_KEY);
14	                  localStorage.removeItem(USER_KEY); },
15	  getToken()    { return this._token; },
16	
17	  saveUser(u)   { localStorage.setItem(USER_KEY, JSON.stringify(u)); },
18	  loadUser()    { try { return JSON.parse(localStorage.getItem(USER_KEY)); }
19	                  catch { return null; } },
20	
21	  /**
22	   * Core request method.
23	   * @returns {{ ok, status, data }}
24	   */
25	  async req(method, path, body = null, opts = {}) {
26	    const headers = { 'Content-Type': 'application/json' };
27	    if (this._token) headers['Authorization'] = `Bearer ${this._token}`;
28	    if (opts.idempotencyKey) headers['Idempotency-Key'] = opts.idempotencyKey;
29	
30	    const fetchOpts = { method, headers };
31	    if (body !== null) fetchOpts.body = JSON.stringify(body);
32	
33	    try {
34	      const res  = await fetch('/api' + path, fetchOpts);
35	      const data = await res.json().catch(() => ({}));
36	
37	      // Automatically handle token expiry
38	      if (res.status === 401 && path !== '/auth/login') {
39	        this.clearToken();
40	        window.location.reload();
41	      }
42	      return { ok: res.ok, status: res.status, data };
43	    } catch (err) {
44	      return { ok: false, status: 0, data: { error: 'Network error. Is the server running?' } };
45	    }
46	  },
47	
48	  get(path, params = {}) {
49	    const q = new URLSearchParams(
50	      Object.fromEntries(Object.entries(params).filter(([, v]) => v !== '' && v != null))
51	    ).toString();
52	    return this.req('GET', path + (q ? '?' + q : ''));
53	  },
54	  post(path, body, opts) { return this.req('POST',   path, body, opts || {}); },
55	  put(path, body)        { return this.req('PUT',    path, body); },
56	  del(path)              { return this.req('DELETE', path); },
57	
58	  /** Generate a random idempotency key */
59	  idemKey() {
60	    return `idem-${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
61	  },
62	};
