10	// ---- Formatting --------------------------------------------------------
11	export function fmtDate(iso) {
12	  if (!iso) return '—';
13	  const d = new Date(iso);
14	  return isNaN(d) ? iso : d.toLocaleString();
15	}
16	
17	export function fmtBalance(n) {
18	  return typeof n === 'number' ? n.toFixed(2) : '—';
19	}
20	
21	/**
22	 * Mask an email: "alice@example.com" → "al***@example.com"
23	 * (Server already masks, but we apply client-side too for belt-and-suspenders.)
24	 */
25	export function maskEmail(email) {
26	  if (!email || !email.includes('@')) return '***';
27	  const [local, domain] = email.split('@');
28	  const visible = local.slice(0, Math.min(2, local.length));
29	  return `${visible}***@${domain}`;
30	}
