32	// ---- Badge & stars -----------------------------------------------------
33	export function badge(status, label) {
34	  const s = (status || '').toLowerCase().replace(/\s/g, '_');
35	  return `<span class="badge badge-${s}">${label || status || '—'}</span>`;
36	}
37	
38	export function stars(score, total = 5) {
39	  if (score == null || score === '') return '<span class="stars">—</span>';
40	  const n    = Math.round(+score);
41	  const full = '★'.repeat(Math.min(n, total));
42	  const empty= '☆'.repeat(Math.max(0, total - n));
43	  return `<span class="stars">${full}${empty}</span> <small>${(+score).toFixed(1)}</small>`;
44	}
