46	// ---- Alert banner ------------------------------------------------------
47	let _alertTimer = null;
48	export function showAlert(html, type = 'info', containerId = 'main-alert') {
49	  const c = el(containerId);
50	  if (!c) return;
51	  if (_alertTimer) clearTimeout(_alertTimer);
52	  c.innerHTML = `<div class="alert alert-${type}">${html}</div>`;
53	  _alertTimer = setTimeout(() => { c.innerHTML = ''; }, 5500);
54	}
