56	// ---- Modal -------------------------------------------------------------
57	export function showModal(html, onClose) {
58	  let overlay = el('modal-overlay');
59	  if (!overlay) {
60	    overlay = document.createElement('div');
61	    overlay.id = 'modal-overlay';
62	    overlay.className = 'modal-overlay';
63	    document.body.appendChild(overlay);
64	  }
65	  overlay.innerHTML = `<div class="modal" role="dialog">${html}</div>`;
66	  overlay.style.display = 'flex';
67	
68	  const closeBtn = overlay.querySelector('.modal-close');
69	  const doClose  = () => { closeModal(); onClose?.(); };
70	  closeBtn?.addEventListener('click', doClose);
71	  overlay.addEventListener('click', e => { if (e.target === overlay) doClose(); });
72	}
73	
74	export function closeModal() {
75	  const o = el('modal-overlay');
76	  if (o) o.style.display = 'none';
77	}
