79	// ---- Pagination control ------------------------------------------------
80	export function buildPagination(total, page, perPage, onPage) {
81	  const totalPages = Math.ceil(total / perPage);
82	  if (totalPages <= 1) return '';
83	  const prevDis = page <= 1 ? 'disabled' : '';
84	  const nextDis = page >= totalPages ? 'disabled' : '';
85	  const wrap = `
86	    <div class="pagination">
87	      <span class="pg-info">Page ${page} of ${totalPages} &nbsp;(${total} total)</span>
88	      <button class="btn btn-sm btn-secondary" ${prevDis} data-pg="${page-1}">‹ Prev</button>
89	      <button class="btn btn-sm btn-secondary" ${nextDis} data-pg="${page+1}">Next ›</button>
90	    </div>`;
91	  // Attach after next tick (element must be in DOM)
92	  setTimeout(() => {
93	    qsa('[data-pg]').forEach(b => {
94	      if (!b.disabled) b.addEventListener('click', () => onPage(+b.dataset.pg));
95	    });
96	  }, 0);
97	  return wrap;
98	}
