100	// ---- Star-rating input widget ------------------------------------------
101	export function buildStarInput(name = 'score', defaultVal = 0) {
102	  const stars = [5, 4, 3, 2, 1];
103	  const radios = stars.map(n => `
104	    <input type="radio" name="${name}" id="${name}_${n}" value="${n}"
105	           ${n === defaultVal ? 'checked' : ''}>
106	    <label for="${name}_${n}" title="${n} star${n > 1 ? 's' : ''}" data-v="${n}">★</label>
107	  `).join('');
108	  return `<div class="stars-input" id="${name}-widget">${radios}</div>`;
109	}
