let _pollTimer    = null;
let _pollEntryId  = null;
let _pollSkill    = '';
let _pollAttempts = 0;
const POLL_INTERVAL_MS = 10_000;

function startPolling(entryId, skill) {
  stopPolling();
  _pollEntryId  = entryId;
  _pollSkill    = skill;
  _pollAttempts = 0;
  _pollTimer    = setInterval(_pollQueueEntry, POLL_INTERVAL_MS);
}

function stopPolling() {
  if (_pollTimer) { clearInterval(_pollTimer); _pollTimer = null; }
  _pollEntryId = null;
}

async function _pollQueueEntry() {
  if (!_pollEntryId) return;
  _pollAttempts++;

  const { ok, data } = await API.get(`/matching/queue/${_pollEntryId}`);
  if (!ok) return; // network hiccup — keep trying

  const entry  = data.entry;
  const card   = el('match-status-card');
  const meta   = el('poll-meta');
  if (meta) meta.textContent = `Last checked: just now · attempt ${_pollAttempts}`;

  if (entry.status === 'matched') {
