    _renderMatchState(card, 'found', entry);
  } else if (entry.status === 'expired' || entry.status === 'cancelled') {
    stopPolling();
    _renderMatchState(card, 'retrying', entry);
  }
  // else still 'waiting' — leave 'searching' state as-is
