      </a>
      <div class="match-poll-meta">Session #${entry.session_id}</div>`,

    retrying: `
      <div class="state-icon">🔄</div>
      <h3 style="color:var(--c-warn)">No Match Yet</h3>
      <p>Your queue entry expired. Try joining again.</p>
      <button class="btn btn-warn btn-lg" id="btn-rejoin">Rejoin Queue</button>
      <div class="match-poll-meta">Skill: ${entry.skill}</div>`,

    searching: `
      <div class="state-icon pulse"><div class="spinner" style="margin:0 auto"></div></div>
      <h3 style="color:var(--c-accent);margin-top:.5rem">Searching…</h3>
      <p>Looking for a peer who offers <strong>${entry.skill}</strong>.</p>
      <button class="btn btn-ghost btn-sm" id="btn-cancel-queue">Cancel</button>
      <div class="match-poll-meta" id="poll-meta">Polling every 10 s</div>`,
  };

  card.innerHTML = content[state] || '';

  if (state === 'retrying') {
    el('btn-rejoin')?.addEventListener('click', () => {
      renderQueueSection(entry.skill);
    });
  }
  if (state === 'searching') {
    el('btn-cancel-queue')?.addEventListener('click', async () => {
      await API.put(`/matching/queue/${_pollEntryId}/cancel`);
      stopPolling();
      card.remove();
      showAlert('Queue entry cancelled.', 'info');
    });
  }
